{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleLambdaTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test cases for lambda indentation issue where lambda parameters that should not be wrapped
 * are being wrapped incorrectly due to a bug in how we detect if the first parameter is preceded by a newline.
 */
internal class IndentationRuleLambdaTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `lambda with single parameter on same line should not be reindented incorrectly`() {
        val code =
            """
            val foo = { size -> icon?.getBitmap(size)?.await() }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `lambda body on separate line should be indented normally`() {
        val code =
            """
            val foo = { size ->
                icon?.getBitmap(size)?.await()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `lambda with multiple parameters originally on same line should not be double indented`() {
        val code =
            """
            val foo = { a, b, c ->
                doSomething()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `lambda with parameters actually on multiple lines should have double indent for parameters`() {
        val code =
            """
            val foo = {
                a,
                b,
                c ->
                doSomething()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}"}

